import{_ as o,c as t,o as d,ag as r}from"./chunks/framework.Bw-5EFTY.js";const m=JSON.parse('{"title":"Google Specification","description":"","frontmatter":{},"headers":[],"relativePath":"packages/google/SPEC.md","filePath":"packages/google/SPEC.md"}'),c={name:"packages/google/SPEC.md"};function a(s,e,i,n,l,p){return d(),t("div",null,e[0]||(e[0]=[r('<h1 id="google-specification" tabindex="-1">Google Specification <a class="header-anchor" href="#google-specification" aria-label="Permalink to &quot;Google Specification&quot;">​</a></h1><h2 id="scope" tabindex="-1">Scope <a class="header-anchor" href="#scope" aria-label="Permalink to &quot;Scope&quot;">​</a></h2><ul><li>Owns the Google AI (Gemini) provider integration for Robota SDK.</li><li>Implements <code>AbstractAIProvider</code> from <code>@robota-sdk/agents</code> to provide Gemini model access through the Google Generative AI SDK.</li><li>Implements <code>IImageGenerationProvider</code> from <code>@robota-sdk/agents</code> to provide image generation, editing, and composition capabilities.</li><li>Owns Google-specific message format conversion (universal to/from Gemini wire format), including multipart content with inline image data.</li><li>Owns Google-specific tool call format conversion (<code>functionDeclarations</code>-based tools).</li><li>Owns provider option types (<code>IGoogleProviderOptions</code>, <code>TGoogleProviderOptionValue</code>).</li><li>Owns Google AI API type definitions for messages, requests, responses, streaming, tools, safety ratings, and errors.</li><li>Owns response modality logic (TEXT, IMAGE) and image-capable model validation.</li></ul><h2 id="boundaries" tabindex="-1">Boundaries <a class="header-anchor" href="#boundaries" aria-label="Permalink to &quot;Boundaries&quot;">​</a></h2><ul><li>Does not own generic agent orchestration, message types, or provider abstractions; those belong to <code>@robota-sdk/agents</code>.</li><li>Does not own executor contracts (<code>IExecutor</code>); imports them from <code>@robota-sdk/agents</code>.</li><li>Does not own <code>TUniversalMessage</code>, <code>IChatOptions</code>, <code>IToolSchema</code>, <code>IAssistantMessage</code>, <code>IUserMessage</code>, <code>ISystemMessage</code>, <code>IToolMessage</code>, <code>TUniversalMessagePart</code>, or image generation interfaces; imports them from <code>@robota-sdk/agents</code>.</li><li>Does not own session management, team collaboration, or workflow concerns.</li><li>Keeps all Google-specific transport behavior explicit and provider-scoped.</li></ul><h2 id="architecture-overview" tabindex="-1">Architecture Overview <a class="header-anchor" href="#architecture-overview" aria-label="Permalink to &quot;Architecture Overview&quot;">​</a></h2><p>The package follows a provider-adapter pattern with additional image generation support:</p><ol><li><p><strong><code>GoogleProvider</code></strong> (<code>provider.ts</code>) -- the primary class. Extends <code>AbstractAIProvider</code> and implements <code>IImageGenerationProvider</code>. Provides <code>chat()</code>, <code>chatStream()</code>, <code>generateImage()</code>, <code>editImage()</code>, <code>composeImage()</code>, <code>supportsTools()</code>, <code>validateConfig()</code>, and <code>dispose()</code>. Converts between <code>TUniversalMessage</code> (including multipart with inline images) and Gemini <code>contents</code> format. Supports both direct API execution (via <code>@google/generative-ai</code> SDK) and delegated execution (via <code>IExecutor</code>).</p></li><li><p><strong>Types layer</strong> (<code>types.ts</code>, <code>types/api-types.ts</code>) -- provider option interface and Google AI-specific API type definitions covering content, requests, responses, streaming, tools, safety ratings, citation metadata, and errors.</p></li><li><p><strong>Entry point</strong> (<code>index.ts</code>) -- re-exports <code>provider.ts</code> and <code>types.ts</code>.</p></li></ol><p>Key internal methods:</p><ul><li><code>convertToGeminiFormat()</code> -- maps <code>TUniversalMessage[]</code> to Gemini <code>contents</code> array, handling user, assistant (model), tool, and system roles. Supports <code>parts</code>-based messages with text and inline image data.</li><li><code>convertFromGeminiResponse()</code> -- extracts text parts, inline image parts, and function calls from Gemini candidates into <code>TUniversalMessage</code> with <code>parts</code> array.</li><li><code>buildResponseModalities()</code> -- determines whether to request TEXT, IMAGE, or both based on chat options, input message content, and provider defaults.</li><li><code>buildGenerationConfig()</code> -- constructs generation config including modality validation against image-capable models.</li><li><code>runImageRequest()</code> -- shared execution path for <code>generateImage()</code>, <code>editImage()</code>, and <code>composeImage()</code>, delegating to <code>chat()</code> with IMAGE modality.</li><li><code>mapImageInputSourceToPart()</code> -- validates and converts image input sources (inline or data URI) to <code>TUniversalMessagePart</code>.</li></ul><p>Dependency direction: <code>@robota-sdk/google</code> depends on <code>@robota-sdk/agents</code> (peer dependency) and <code>@google/generative-ai</code> (direct dependency). No other workspace packages are imported.</p><h2 id="type-ownership" tabindex="-1">Type Ownership <a class="header-anchor" href="#type-ownership" aria-label="Permalink to &quot;Type Ownership&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Type</th><th>Owner</th><th>Location</th></tr></thead><tbody><tr><td><code>IGoogleProviderOptions</code></td><td><code>@robota-sdk/google</code></td><td><code>src/types.ts</code></td></tr><tr><td><code>TGoogleProviderOptionValue</code></td><td><code>@robota-sdk/google</code></td><td><code>src/types.ts</code></td></tr><tr><td><code>IGoogleModelConfig</code></td><td><code>@robota-sdk/google</code></td><td><code>src/types/api-types.ts</code></td></tr><tr><td><code>IGoogleGenerateContentRequest</code></td><td><code>@robota-sdk/google</code></td><td><code>src/types/api-types.ts</code></td></tr><tr><td><code>IGoogleStreamGenerateContentRequest</code></td><td><code>@robota-sdk/google</code></td><td><code>src/types/api-types.ts</code></td></tr><tr><td><code>IGoogleContent</code></td><td><code>@robota-sdk/google</code></td><td><code>src/types/api-types.ts</code></td></tr><tr><td><code>IGooglePart</code></td><td><code>@robota-sdk/google</code></td><td><code>src/types/api-types.ts</code></td></tr><tr><td><code>IGoogleFunctionCall</code></td><td><code>@robota-sdk/google</code></td><td><code>src/types/api-types.ts</code></td></tr><tr><td><code>IGoogleFunctionResponse</code></td><td><code>@robota-sdk/google</code></td><td><code>src/types/api-types.ts</code></td></tr><tr><td><code>IGoogleTool</code></td><td><code>@robota-sdk/google</code></td><td><code>src/types/api-types.ts</code></td></tr><tr><td><code>IGoogleFunctionDeclaration</code></td><td><code>@robota-sdk/google</code></td><td><code>src/types/api-types.ts</code></td></tr><tr><td><code>IGoogleFunctionParameters</code></td><td><code>@robota-sdk/google</code></td><td><code>src/types/api-types.ts</code></td></tr><tr><td><code>IGooglePropertySchema</code></td><td><code>@robota-sdk/google</code></td><td><code>src/types/api-types.ts</code></td></tr><tr><td><code>IGoogleGenerateContentResponse</code></td><td><code>@robota-sdk/google</code></td><td><code>src/types/api-types.ts</code></td></tr><tr><td><code>IGoogleCandidate</code></td><td><code>@robota-sdk/google</code></td><td><code>src/types/api-types.ts</code></td></tr><tr><td><code>TGoogleFinishReason</code></td><td><code>@robota-sdk/google</code></td><td><code>src/types/api-types.ts</code></td></tr><tr><td><code>IGoogleSafetyRating</code></td><td><code>@robota-sdk/google</code></td><td><code>src/types/api-types.ts</code></td></tr><tr><td><code>TGoogleHarmCategory</code></td><td><code>@robota-sdk/google</code></td><td><code>src/types/api-types.ts</code></td></tr><tr><td><code>TGoogleHarmProbability</code></td><td><code>@robota-sdk/google</code></td><td><code>src/types/api-types.ts</code></td></tr><tr><td><code>IGoogleCitationMetadata</code></td><td><code>@robota-sdk/google</code></td><td><code>src/types/api-types.ts</code></td></tr><tr><td><code>IGoogleCitationSource</code></td><td><code>@robota-sdk/google</code></td><td><code>src/types/api-types.ts</code></td></tr><tr><td><code>IGooglePromptFeedback</code></td><td><code>@robota-sdk/google</code></td><td><code>src/types/api-types.ts</code></td></tr><tr><td><code>TGoogleBlockReason</code></td><td><code>@robota-sdk/google</code></td><td><code>src/types/api-types.ts</code></td></tr><tr><td><code>IGoogleUsageMetadata</code></td><td><code>@robota-sdk/google</code></td><td><code>src/types/api-types.ts</code></td></tr><tr><td><code>IGoogleStreamChunk</code></td><td><code>@robota-sdk/google</code></td><td><code>src/types/api-types.ts</code></td></tr><tr><td><code>IGoogleError</code></td><td><code>@robota-sdk/google</code></td><td><code>src/types/api-types.ts</code></td></tr><tr><td><code>IGoogleErrorDetail</code></td><td><code>@robota-sdk/google</code></td><td><code>src/types/api-types.ts</code></td></tr><tr><td><code>IGoogleLogData</code></td><td><code>@robota-sdk/google</code></td><td><code>src/types/api-types.ts</code></td></tr><tr><td><code>IGoogleToolCall</code></td><td><code>@robota-sdk/google</code></td><td><code>src/types/api-types.ts</code></td></tr><tr><td><code>IGoogleMessageConversionResult</code></td><td><code>@robota-sdk/google</code></td><td><code>src/types/api-types.ts</code></td></tr><tr><td><code>IGoogleStreamContext</code></td><td><code>@robota-sdk/google</code></td><td><code>src/types/api-types.ts</code></td></tr><tr><td><code>GoogleProvider</code></td><td><code>@robota-sdk/google</code></td><td><code>src/provider.ts</code></td></tr></tbody></table><p>Imported from <code>@robota-sdk/agents</code> (not owned): <code>AbstractAIProvider</code>, <code>TUniversalMessage</code>, <code>IChatOptions</code>, <code>IToolSchema</code>, <code>IAssistantMessage</code>, <code>IUserMessage</code>, <code>ISystemMessage</code>, <code>IToolMessage</code>, <code>TUniversalMessagePart</code>, <code>IImageGenerationProvider</code>, <code>IImageGenerationRequest</code>, <code>IImageEditRequest</code>, <code>IImageComposeRequest</code>, <code>IImageGenerationResult</code>, <code>IMediaOutputRef</code>, <code>TProviderMediaResult</code>, <code>IExecutor</code>, <code>TProviderOptionValueBase</code>.</p><h2 id="public-api-surface" tabindex="-1">Public API Surface <a class="header-anchor" href="#public-api-surface" aria-label="Permalink to &quot;Public API Surface&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Export</th><th>Kind</th><th>Source</th><th>Description</th></tr></thead><tbody><tr><td><code>GoogleProvider</code></td><td>class</td><td><code>src/provider.ts</code></td><td>Google Gemini provider implementing <code>AbstractAIProvider</code> and <code>IImageGenerationProvider</code>. Methods: <code>chat()</code>, <code>chatStream()</code>, <code>generateImage()</code>, <code>editImage()</code>, <code>composeImage()</code>, <code>supportsTools()</code>, <code>validateConfig()</code>, <code>dispose()</code>.</td></tr><tr><td><code>IGoogleProviderOptions</code></td><td>interface</td><td><code>src/types.ts</code></td><td>Configuration options for constructing <code>GoogleProvider</code>. Fields: <code>apiKey</code> (required), <code>responseMimeType</code>, <code>responseSchema</code>, <code>defaultResponseModalities</code>, <code>imageCapableModels</code>, <code>executor</code>, plus index signature.</td></tr><tr><td><code>TGoogleProviderOptionValue</code></td><td>type alias</td><td><code>src/types.ts</code></td><td>Union type for valid provider option values.</td></tr><tr><td>All types from <code>src/types/api-types.ts</code></td><td>interfaces/types</td><td><code>src/types/api-types.ts</code></td><td>Google AI API type definitions (content, requests, responses, tools, safety, streaming, errors). Exported transitively via <code>src/types.ts</code> re-export pattern.</td></tr></tbody></table><h2 id="extension-points" tabindex="-1">Extension Points <a class="header-anchor" href="#extension-points" aria-label="Permalink to &quot;Extension Points&quot;">​</a></h2><ul><li><strong>Executor injection</strong>: The provider accepts an <code>IExecutor</code> via <code>IGoogleProviderOptions.executor</code>, enabling delegation of chat operations to local or remote executors without modifying the provider.</li><li><strong>Response modalities configuration</strong>: <code>IGoogleProviderOptions.defaultResponseModalities</code> allows default modality configuration (TEXT, IMAGE). Per-request overrides are available via <code>IChatOptions.google.responseModalities</code>.</li><li><strong>Image-capable model allowlist</strong>: <code>IGoogleProviderOptions.imageCapableModels</code> overrides the default model-name heuristic for image capability detection.</li><li><strong>Response format configuration</strong>: <code>responseMimeType</code> and <code>responseSchema</code> options allow requesting structured JSON output from Gemini.</li><li><strong>AbstractAIProvider contract</strong>: New lifecycle or capability methods added to <code>AbstractAIProvider</code> in <code>@robota-sdk/agents</code> can be overridden in <code>GoogleProvider</code>.</li></ul><h2 id="error-taxonomy" tabindex="-1">Error Taxonomy <a class="header-anchor" href="#error-taxonomy" aria-label="Permalink to &quot;Error Taxonomy&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Error Condition</th><th>Thrown By</th><th>Message Pattern</th></tr></thead><tbody><tr><td>Client unavailable during direct execution</td><td><code>chat()</code>, <code>chatStream()</code></td><td><code>&quot;Google client not available. Either provide apiKey or use an executor.&quot;</code></td></tr><tr><td>Missing model in chat options</td><td><code>chat()</code>, <code>chatStream()</code></td><td><code>&quot;Model is required in IChatOptions. Please specify a model in defaultModel configuration.&quot;</code></td></tr><tr><td>No candidate in response</td><td><code>convertFromGeminiResponse()</code></td><td><code>&quot;No candidate in Gemini response&quot;</code></td></tr><tr><td>No content in response</td><td><code>convertFromGeminiResponse()</code></td><td><code>&quot;No content in Gemini response&quot;</code></td></tr><tr><td>Unsupported image URI parts</td><td><code>mapMessagePartsToGeminiParts()</code></td><td><code>&quot;Google provider does not support image URI parts directly: &lt;uri&gt;&quot;</code></td></tr><tr><td>Non-image-capable model with IMAGE modality</td><td><code>buildGenerationConfig()</code></td><td><code>&quot;Selected model \\&quot;&lt;model&gt;\\&quot; is not configured as image-capable for Google provider.&quot;</code></td></tr><tr><td>IMAGE modality in streaming</td><td><code>chatStream()</code></td><td><code>&quot;Google provider does not support streaming image modality responses.&quot;</code></td></tr><tr><td>Missing image in response when IMAGE requested</td><td><code>chat()</code></td><td><code>&quot;Gemini response did not include an image part while IMAGE modality was requested.&quot;</code></td></tr><tr><td>Chat failure (wraps all direct execution errors)</td><td><code>chat()</code></td><td><code>&quot;Google chat failed: &lt;message&gt;&quot;</code></td></tr><tr><td>Stream failure (wraps all streaming errors)</td><td><code>chatStream()</code></td><td><code>&quot;Google stream failed: &lt;message&gt;&quot;</code></td></tr><tr><td>Empty prompt for image generation</td><td><code>generateImage()</code></td><td>Result: <code>{ ok: false, error: { code: &#39;PROVIDER_INVALID_REQUEST&#39;, message: &#39;...&#39; } }</code></td></tr><tr><td>Empty model for image generation</td><td><code>generateImage()</code></td><td>Result: <code>{ ok: false, error: { code: &#39;PROVIDER_INVALID_REQUEST&#39;, message: &#39;...&#39; } }</code></td></tr><tr><td>Empty prompt for image edit</td><td><code>editImage()</code></td><td>Result: <code>{ ok: false, error: { code: &#39;PROVIDER_INVALID_REQUEST&#39;, message: &#39;...&#39; } }</code></td></tr><tr><td>Empty model for image edit</td><td><code>editImage()</code></td><td>Result: <code>{ ok: false, error: { code: &#39;PROVIDER_INVALID_REQUEST&#39;, message: &#39;...&#39; } }</code></td></tr><tr><td>Invalid inline image source</td><td><code>mapImageInputSourceToPart()</code></td><td>Result: <code>{ ok: false, error: { code: &#39;PROVIDER_INVALID_REQUEST&#39;, message: &#39;...&#39; } }</code></td></tr><tr><td>Non-data-URI image source</td><td><code>mapImageInputSourceToPart()</code></td><td>Result: <code>{ ok: false, error: { code: &#39;PROVIDER_INVALID_REQUEST&#39;, message: &#39;...&#39; } }</code></td></tr><tr><td>Invalid data URI format</td><td><code>mapImageInputSourceToPart()</code></td><td>Result: <code>{ ok: false, error: { code: &#39;PROVIDER_INVALID_REQUEST&#39;, message: &#39;...&#39; } }</code></td></tr><tr><td>Fewer than 2 images for compose</td><td><code>composeImage()</code></td><td>Result: <code>{ ok: false, error: { code: &#39;PROVIDER_INVALID_REQUEST&#39;, message: &#39;...&#39; } }</code></td></tr><tr><td>Upstream image generation failure</td><td><code>runImageRequest()</code></td><td>Result: <code>{ ok: false, error: { code: &#39;PROVIDER_UPSTREAM_ERROR&#39;, message: &#39;...&#39; } }</code></td></tr></tbody></table><p>Note: Image generation methods (<code>generateImage</code>, <code>editImage</code>, <code>composeImage</code>) return <code>TProviderMediaResult</code> (a discriminated union with <code>ok: true | false</code>) rather than throwing. Chat methods throw errors directly.</p><p>Google API errors are defined in <code>IGoogleError</code> with numeric <code>code</code>, string <code>status</code>, and optional <code>details</code> array.</p><h2 id="class-contract-registry" tabindex="-1">Class Contract Registry <a class="header-anchor" href="#class-contract-registry" aria-label="Permalink to &quot;Class Contract Registry&quot;">​</a></h2><h3 id="interface-implementations" tabindex="-1">Interface Implementations <a class="header-anchor" href="#interface-implementations" aria-label="Permalink to &quot;Interface Implementations&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Interface</th><th>Implementor</th><th>Kind</th><th>Location</th></tr></thead><tbody><tr><td><code>IImageGenerationProvider</code></td><td><code>GoogleProvider</code></td><td>production</td><td><code>src/provider.ts</code></td></tr></tbody></table><h3 id="inheritance-chains" tabindex="-1">Inheritance Chains <a class="header-anchor" href="#inheritance-chains" aria-label="Permalink to &quot;Inheritance Chains&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Base (Owner)</th><th>Derived</th><th>Location</th><th>Notes</th></tr></thead><tbody><tr><td><code>AbstractAIProvider</code> (agents)</td><td><code>GoogleProvider</code></td><td><code>src/provider.ts</code></td><td>Provider with image generation</td></tr></tbody></table><h3 id="cross-package-port-consumers" tabindex="-1">Cross-Package Port Consumers <a class="header-anchor" href="#cross-package-port-consumers" aria-label="Permalink to &quot;Cross-Package Port Consumers&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Port (Owner)</th><th>Adapter</th><th>Location</th></tr></thead><tbody><tr><td><code>AbstractAIProvider</code> (agents)</td><td><code>GoogleProvider</code></td><td><code>src/provider.ts</code></td></tr><tr><td><code>IImageGenerationProvider</code> (agents)</td><td><code>GoogleProvider</code></td><td><code>src/provider.ts</code></td></tr></tbody></table><h2 id="test-strategy" tabindex="-1">Test Strategy <a class="header-anchor" href="#test-strategy" aria-label="Permalink to &quot;Test Strategy&quot;">​</a></h2><ul><li><strong>Current state</strong>: One test file exists at <code>src/provider.spec.ts</code> covering image-related functionality.</li><li><strong>Existing test coverage</strong>: <ul><li>Inline image output mapping from Gemini response to assistant <code>parts</code>.</li><li>Inline image input parts mapped correctly into Gemini <code>inlineData</code> request parts.</li><li>Error when IMAGE modality is requested with a non-image-capable model.</li><li>Error when <code>image_uri</code> message part type is used directly.</li></ul></li><li><strong>Recommended additional coverage</strong>: <ul><li>Unit tests for <code>GoogleProvider</code> constructor validation (apiKey vs executor).</li><li>Unit tests for text-only message format conversion (<code>convertToGeminiFormat</code>) across all roles (user, assistant, system, tool).</li><li>Unit tests for <code>convertFromGeminiResponse()</code> with function calls and usage metadata.</li><li>Unit tests for tool schema conversion (<code>convertToolsToGeminiFormat</code>).</li><li>Unit tests for <code>generateImage()</code>, <code>editImage()</code>, and <code>composeImage()</code> input validation (empty prompt, empty model, too few images).</li><li>Unit tests for <code>mapImageInputSourceToPart()</code> with various source types and edge cases.</li><li>Unit tests for <code>buildResponseModalities()</code> logic (option override, image input detection, default fallback).</li><li>Unit tests for <code>chatStream()</code> with mocked streaming responses.</li><li>Unit tests for <code>validateConfig()</code>.</li></ul></li><li><strong>Framework</strong>: Vitest (configured in workspace).</li><li><strong>Test commands</strong>: <code>pnpm test</code>, <code>pnpm test:watch</code>, <code>pnpm test:coverage</code>.</li><li><strong>Scenario verification</strong>: <code>pnpm scenario:verify</code>, <code>pnpm scenario:record</code> (image dry-run scenarios).</li></ul>',31)]))}const u=o(c,[["render",a]]);export{m as __pageData,u as default};
